const html = $input.first().json.data || $input.first().json.body || '';
const chapterNum = $('Set Input').first().json.chapter_number;

// Extract chapter links from HTML
const linkPattern = /href=["']([^"']*\/(\d+)\.html)["'][^>]*>([^<]*第[^<]*章[^<]*)/gi;
const chapters = [];
let match;

while ((match = linkPattern.exec(html)) !== null) {
  chapters.push({
    url: match[1],
    id: match[2],
    title: match[3].trim()
  });
}

// Find target chapter
const target = chapters[chapterNum - 1];

if (!target) {
  return [{ json: { error: `Chapter ${chapterNum} not found. Total chapters: ${chapters.length}` } }];
}

const baseUrl = $('Lookup Novel').first().json.base_url;
const fullUrl = target.url.startsWith('http') ? target.url : baseUrl + target.url.split('/').pop();

return [{ json: { chapter_url: fullUrl, chapter_title: target.title, chapter_number: chapterNum } }];

const html = $input.first().json.data || $input.first().json.body || '';

// Extract main content - remove HTML tags, scripts, styles
let text = html
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, '\n')
  .replace(/&nbsp;/g, ' ')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&amp;/g, '&')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

// Remove common noise patterns
text = text
  .replace(/.*书海阁.*\n?/g, '')
  .replace(/.*shuhaige.*\n?/g, '')
  .replace(/.*上一章.*下一章.*/g, '')
  .replace(/.*加入书签.*/g, '')
  .replace(/.*返回目录.*/g, '')
  .trim();

// Find the actual chapter content (usually between specific markers)
const lines = text.split('\n').filter(l => l.trim().length > 0);

// Remove first few lines (navigation) and last few (ads)
const contentLines = lines.filter(line => {
  const l = line.trim();
  return l.length > 10 && !l.includes('书海阁') && !l.includes('上一章') && !l.includes('下一章') && !l.includes('加入书签');
});

const chapterText = contentLines.join('\n\n');
const chapterInfo = $('Parse Chapter URL').first().json;

return [{
  json: {
    chapter_text: chapterText,
    chapter_title: chapterInfo.chapter_title,
    chapter_number: chapterInfo.chapter_number,
    chapter_url: chapterInfo.chapter_url,
    char_count: chapterText.length
  }
}];

const glossaryItems = $input.all().map(i => i.json);
const chapterData = $('Extract Text').first().json;

// Build glossary string for prompt
const glossaryStr = glossaryItems.map(g => `${g.term_cn} → ${g.term_vn}`).join('\n');

const systemPrompt = `你是一位专业的中越文学翻译家，专注于仙侠/玄幻小说翻译。

翻译要求：
1. 保持原文的文学风格和韵味
2. 人称代词：他→hắn（男性）, 她→nàng（女性）
3. 使用下方术语表翻译专有名词，未在表中的保留原文并注音
4. 保留原文段落结构
5. 不添加解释或注释
6. 翻译成自然流畅的越南语

术语表：
${glossaryStr}`;

const userPrompt = `请将以下中文小说章节翻译成越南语：

${chapterData.chapter_text}`;

return [{
  json: {
    system_prompt: systemPrompt,
    user_prompt: userPrompt,
    chapter_title: chapterData.chapter_title,
    chapter_number: chapterData.chapter_number,
    chapter_url: chapterData.chapter_url,
    original_text: chapterData.chapter_text,
    char_count: chapterData.char_count
  }
}];

function escapeSql(str) { return str ? str.replace(/'/g, "''") : ''; }

const response = $input.first().json;
const prepData = $('Prepare Translation').first().json;
const novelData = $('Lookup Novel').first().json;

const translatedText = response.message?.content || 'Translation failed';

return [{
  json: {
    novel_id: novelData.id,
    title_cn: novelData.title_cn,
    title_vn: novelData.title_vn,
    author: novelData.author,
    chapter_number: prepData.chapter_number,
    chapter_title: escapeSql(prepData.chapter_title),
    chapter_url: escapeSql(prepData.chapter_url),
    original_text: escapeSql(prepData.original_text),
    translated_text: escapeSql(translatedText),
    translated_text_raw: translatedText,
    char_count: prepData.char_count
  }
}];

const data = $('Parse Translation').first().json;
const text = data.translated_text_raw;

// Telegram max 4096 chars - split into messages
const MAX_LEN = 3800;
const messages = [];

// First message with header
let header = `📖 *${data.title_cn} - ${data.title_vn}*\n`;
header += `📑 *Chương ${data.chapter_number}: ${data.chapter_title.replace(/'/g, '')}*\n`;
header += `👤 ${data.author}\n\n---\n\n`;

if (header.length + text.length <= MAX_LEN) {
  messages.push(header + text + `\n\n---\n📊 ${data.char_count} chữ | 🤖 Qwen2 7B`);
} else {
  // Split text into chunks
  const chunks = [];
  let remaining = text;
  while (remaining.length > 0) {
    if (remaining.length <= MAX_LEN - 200) {
      chunks.push(remaining);
      break;
    }
    // Find paragraph break near limit
    let splitAt = remaining.lastIndexOf('\n\n', MAX_LEN - 200);
    if (splitAt < MAX_LEN / 2) splitAt = remaining.lastIndexOf('\n', MAX_LEN - 200);
    if (splitAt < MAX_LEN / 2) splitAt = MAX_LEN - 200;
    chunks.push(remaining.substring(0, splitAt));
    remaining = remaining.substring(splitAt).trim();
  }

  messages.push(header + chunks[0]);
  for (let i = 1; i < chunks.length; i++) {
    if (i === chunks.length - 1) {
      messages.push(chunks[i] + `\n\n---\n📊 ${data.char_count} chữ | 🤖 Qwen2 7B`);
    } else {
      messages.push(chunks[i]);
    }
  }
}

return messages.map((msg, i) => ({ json: { message: msg, part: i + 1, total: messages.length } }));
